#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100
#define MAX_W 100000000

// Define the structure for a tree node
typedef struct Node {
    int id;
    int weight;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new tree node
Node* createNode(int id) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->id = id;
    node->weight = 0;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**) realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to calculate the maximum total weight of edges for a node
int calculateMaxWeight(Node* node, int d, int* visited) {
    if (node->numChildren == 0) {
        return node->weight;
    }
    int maxWeight = 0;
    for (int i = 0; i < node->numChildren; i++) {
        if (!visited[node->children[i]->id]) {
            visited[node->children[i]->id] = 1;
            maxWeight += calculateMaxWeight(node->children[i], d, visited);
            visited[node->children[i]->id] = 0;
        }
    }
    if (maxWeight > d) {
        maxWeight = d;
    }
    return maxWeight;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n, d;
        scanf("%d %d", &n, &d);
        Node** nodes = (Node**) malloc(n * sizeof(Node*));
        for (int i = 0; i < n; i++) {
            nodes[i] = createNode(i);
        }
        for (int i = 0; i < n - 1; i++) {
            int u, v, w;
            scanf("%d %d %d", &u, &v, &w);
            nodes[u]->weight += w;
            nodes[v]->weight += w;
            addChild(nodes[u], nodes[v]);
            addChild(nodes[v], nodes[u]);
        }
        int maxWeight = 0;
        int* visited = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            visited[i] = 0;
        }
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                visited[i] = 1;
                maxWeight += calculateMaxWeight(nodes[i], d, visited);
                visited[i] = 0;
            }
        }
        printf("%d\n", maxWeight);
    }
    return 0;
}

