import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int id;
        int weight;
        ArrayList<Node> children;

        public Node(int id) {
            this.id = id;
            this.weight = 0;
            this.children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    public static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    // Function to calculate the maximum total weight of edges for a node
    public static int calculateMaxWeight(Node node, int d, boolean[] visited) {
        if (node.children.isEmpty()) {
            return node.weight;
        }
        int maxWeight = 0;
        for (Node child : node.children) {
            if (!visited[child.id]) {
                visited[child.id] = true;
                maxWeight += calculateMaxWeight(child, d, visited);
                visited[child.id] = false;
            }
        }
        if (maxWeight > d) {
            maxWeight = d;
        }
        return maxWeight;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int d = scanner.nextInt();
            Node[] nodes = new Node[n];
            for (int i = 0; i < n; i++) {
                nodes[i] = new Node(i);
            }
            for (int i = 0; i < n - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                int w = scanner.nextInt();
                nodes[u].weight += w;
                nodes[v].weight += w;
                addChild(nodes[u], nodes[v]);
                addChild(nodes[v], nodes[u]);
            }
            int maxWeight = 0;
            boolean[] visited = new boolean[n];
            for (int i = 0; i < n; i++) {
                visited[i] = false;
            }
            for (int i = 0; i < n; i++) {
                if (!visited[i]) {
                    visited[i] = true;
                    maxWeight += calculateMaxWeight(nodes[i], d, visited);
                    visited[i] = false;
                }
            }
            System.out.println(maxWeight);
        }
    }
}

